\xa0\xa0command.Parameters.Add(new OleDbParameter("customerName", CustomerName Name.Text));
\xa0\xa0OleDbDataReader\xa0reader\xa0=\xa0command.ExecuteReader();
\xa0\xa0//\xa0…
